import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProjectDetails() {
  const { id } = useParams();
  const [project, setProject] = useState(null);
  const [userRole, setUserRole] = useState('');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    fetchProject();
    getUserRole();
  }, [id]);

  const getUserRole = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUserRole(response.data.role);
    } catch (error) {
      console.error('Error fetching user role:', error);
    }
  };

  const fetchProject = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get(`http://127.0.0.1:8000/api/projects/${id}/`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProject(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching project:', error);
      setLoading(false);
    }
  };

  if (loading) return <div>Loading...</div>;
  if (!project) return <div>Project not found</div>;

  return (
    <div className="container">
      <button onClick={() => navigate('/projects')}>← Back to Projects</button>

      <h2>{project.title}</h2>

      <div className="project-detail-card">
        <p><strong>Description:</strong> {project.description}</p>
        <p><strong>Skills Required:</strong> {project.skills_required}</p>
        <p><strong>Budget:</strong> ₹{project.budget_min} - ₹{project.budget_max}</p>
        <p><strong>Duration:</strong> {project.duration_days} days</p>
        <p><strong>Status:</strong> {project.status}</p>
        <p><strong>Posted by:</strong> {project.client_name}</p>
      </div>

      {userRole === 'FREELANCER' && (
        <button onClick={() => navigate(`/proposals/create/${id}`)}>
          Apply for this Project
        </button>
      )}
    </div>
  );
}

export default ProjectDetails;
