import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';

function ProposalForm() {
  const { projectId } = useParams();
  const [project, setProject] = useState(null);
  const [formData, setFormData] = useState({
    cover_letter: '',
    bid_amount: '',
    estimated_days: ''
  });
  const navigate = useNavigate();

  useEffect(() => {
    fetchProject();
  }, [projectId]);

  const fetchProject = async () => {
    try {
      const token = localStorage.getItem('access');
      const response = await axios.get(`http://127.0.0.1:8000/api/projects/${projectId}/`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setProject(response.data);
    } catch (error) {
      console.error('Error fetching project:', error);
    }
  };

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.post('http://127.0.0.1:8000/api/proposals/create/', {
        project: projectId,
        ...formData
      }, {
        headers: { Authorization: `Bearer ${token}` }
      });
      alert('Proposal submitted successfully!');
      navigate('/projects');
    } catch (error) {
      console.error('Error submitting proposal:', error);
      alert('Failed to submit proposal');
    }
  };

  if (!project) return <div>Loading...</div>;

  return (
    <div className="container">
      <h2>Submit Proposal for: {project.title}</h2>
      <form onSubmit={handleSubmit}>
        <textarea name="cover_letter" placeholder="Cover Letter" onChange={handleChange} required />
        <input type="number" name="bid_amount" placeholder="Bid Amount (₹)" onChange={handleChange} required />
        <input type="number" name="estimated_days" placeholder="Estimated Days" onChange={handleChange} required />
        <button type="submit">Submit Proposal</button>
      </form>
    </div>
  );
}

export default ProposalForm;
